import{_ as e,o as t,c as r,ai as i}from"./chunks/framework.DMjte4z8.js";const m=JSON.parse('{"title":"自定义 UI 框架（Frame API）","description":"","frontmatter":{"title":"自定义 UI 框架（Frame API）","category":"advanced","updated":"2026-05-21T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.82,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/pastebin/e23909d8468ff4942ccea268fbbcafd1.20598","https://warcraft.wiki.gg/wiki/UIOBJECT_Frame"]},"headers":[],"relativePath":"advanced/自定义-ui-框架frame-api.md","filePath":"advanced/自定义-ui-框架frame-api.md","lastUpdated":1779353774000}'),o={name:"advanced/自定义-ui-框架frame-api.md"};function n(d,a,s,l,h,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="自定义-ui-框架-frame-api" tabindex="-1">自定义 UI 框架（Frame API） <a class="header-anchor" href="#自定义-ui-框架-frame-api" aria-label="Permalink to “自定义 UI 框架（Frame API）”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>本节将带你了解 <strong>Frame API（自定义 UI 框架）</strong> 的基本概念。读完本节后，你会明白什么是 UI 框架，以及它能为你创建一个什么样的界面。</p><h3 id="什么是-ui-框架" tabindex="-1">什么是 UI 框架？ <a class="header-anchor" href="#什么是-ui-框架" aria-label="Permalink to “什么是 UI 框架？”">​</a></h3><p>简单来说，<strong>UI 框架（Frame）</strong> 就是你在游戏中看到的各种界面元素——按钮、血条、弹窗、进度条、甚至是输入框，都属于 UI 框架的范畴[^1]。在 RPG 地图中，你经常需要显示角色信息、菜单选项、背包系统等，这些都需要用到 UI 框架。</p><p>Frame API 是暴雪官方提供的创建自定义 UI 的接口，通过它你可以[^1]：</p><ul><li>在屏幕上<strong>显示文本</strong>（比如伤害数字、任务提示）</li><li><strong>显示图片或模型</strong>（如技能图标、角色立绘）</li><li>创建<strong>可交互的界面元素</strong>——按钮、滑块、输入框等[^1]</li></ul><blockquote><p><strong>💡 新手提示</strong>：UI 框架和触发器（Trigger）的关系是这样的：触发器负责&quot;逻辑&quot;，决定&quot;什么时候做什么事&quot;；UI 框架负责&quot;显示&quot;，决定&quot;玩家看到什么&quot;。两者配合才能做出完整的游戏界面。</p></blockquote><h3 id="框架的分类" tabindex="-1">框架的分类 <a class="header-anchor" href="#框架的分类" aria-label="Permalink to “框架的分类”">​</a></h3><p>从功能上，框架可以分为两大类[^1]：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>举例</th></tr></thead><tbody><tr><td><strong>显示型</strong></td><td>纯展示，不响应玩家操作</td><td>文本框、纹理、模型</td></tr><tr><td><strong>交互型</strong></td><td>可以接收玩家输入</td><td>按钮、滑块、输入框</td></tr></tbody></table><p>交互型框架可以通过<strong>脚本事件</strong>（如 OnEnter、OnLeave）来响应玩家的操作[^3]——比如鼠标悬停在按钮上时变色、点击按钮触发某个功能。</p><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>Frame API 是创建自定义游戏界面的核心工具，它让我们能够突破魔兽默认界面的限制，为玩家打造独特的 RPG 体验。下一节，我们将学习如何打开 Frame 编辑器，并创建你的第一个简单框架。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/pastebin/e23909d8468ff4942ccea268fbbcafd1.20598" target="_blank" rel="noreferrer">The Big UI-Frame Tutorial - Hive Workshop</a> — accessed 2026-05-21 [^3]: <a href="https://warcraft.wiki.gg/wiki/UIOBJECT_Frame" target="_blank" rel="noreferrer">Frame - Warcraft Wiki</a> — accessed 2026-05-21</p>',16)])])}const f=e(o,[["render",n]]);export{m as __pageData,f as default};
